        "subjectItemTitle": "Venturi Scrubber",
        "section": "5",
        "requirementNumber": "5.228.3",
        "page": 133,
        "text": "The Permittee shall operate and maintain control equipment such that it achieves a control efficiency\nfor PM < 2.5 micron >= 75 percent control efficiency.",
        "citation": "[Minn. R. 7007.0800, subp. 14, Minn. R. 7007.0800, subp. 2(A)]",
        "referencedIds": [],
